import React from 'react';
import { Cell } from '@salutejs/plasma-web';
import { Avatar } from '@salutejs/plasma-web';
import { IconChevronRight } from '@salutejs/plasma-icons';
export function App() {
    return (
        <div>
            <Cell
                contentLeft={
                    <Avatar size="m" url="https://avatars.githubusercontent.com/u/1813468?v=4" />
                }
                size="m"
                contentRight={<IconChevronRight color="inherit" size="xs" />}
                title="Title"
                subtitle="Subtitle"
                label="Label"
            />
        </div>
    );
}

import React from 'react';
import { Cell , CellTextboxLabel , CellTextboxTitle , CellTextboxSubtitle, CellTextbox } from '@salutejs/plasma-web';
import { Avatar } from '@salutejs/plasma-web';
import { IconChevronRight } from '@salutejs/plasma-icons';
export function App() {
    return (
        <div>
            <Cell
                contentLeft={
                    <Avatar size="m" url="https://avatars.githubusercontent.com/u/1813468?v=4" />
                }
                size="m"
                contentRight={<IconChevronRight color="inherit" size="xs" />}
            >
                <CellTextbox>
                    <CellTextboxLabel>Label</CellTextboxLabel>
                    <CellTextboxTitle>Title</CellTextboxTitle>
                    <CellTextboxSubtitle>Subtitle</CellTextboxSubtitle>
                    <div style={{'font-size': '12px', opacity: 0.4}}>Caption</div>
                </CellTextbox>
            </Cell>
        </div>
    );
}
